const d = $input.first().json;
const rows = (d.predictions || []).map(p => {
  const pct = p.swarm_risk_probability != null ? (p.swarm_risk_probability * 100).toFixed(1) + '%' : (p.error || '?');
  return `  Hive ${String(p.box_id).padStart(2)}: ${(p.risk_level || 'UNKNOWN').padEnd(10)} ${pct}`;
}).join('\n');
console.log(`[SwarmRisk ${d.run_date}] ${d.alert_count} alertas\n${rows}`);
return $input.all();

const d = $input.first().json;
const dates = d.last_date_per_hive || {};
const lines = Object.entries(dates).map(([h,dt]) => `  Hive ${h}: ${dt}`).join('\n');
console.log(`[AlzaUpdate ${d.run_date}] status=${d.status} | rows=${d.total_feat_rows} | elapsed=${d.elapsed_s}s\nLatest dates per hive:\n${lines}`);
return $input.all();

const d = $input.first().json;
const lines = (d.alerts || []).map(a => {
  const pct = a.swarm_risk_probability != null ? (a.swarm_risk_probability * 100).toFixed(1) + '%' : '';
  return `<li><strong>Colmena ${a.box_id}:</strong> ${pct} de riesgo en los próximos 3 días</li>`;
});
const htmlMessage = `
<h2 style='color:#c0392b'>⚠️ Alerta de enjambrazón — ${d.run_date}</h2>
<p>${d.alert_count} colmena(s) en <strong>riesgo ALTO</strong>:</p>
<ul>${lines.join('')}</ul>
<p>Total colmenas analizadas: ${(d.hives || []).length}</p>
<hr/>
<p style='color:#888;font-size:12px'>Bee Monitor · UAB Apiary · TFG Miguel Arpa</p>
`;
const textMessage = [
  `[${d.run_date}] ALERTA ENJAMBRAZON — ${d.alert_count} colmena(s) en riesgo ALTO:`,
  ...(d.alerts || []).map(a => `  Colmena ${a.box_id}: ${a.swarm_risk_probability != null ? (a.swarm_risk_probability*100).toFixed(1)+'%' : '?'}`),
  `Total colmenas: ${(d.hives||[]).length}`
].join('\n');
console.log(textMessage);
return [{ json: { htmlMessage, textMessage, alert_count: d.alert_count, run_date: d.run_date, alerts: d.alerts } }];

const d = $input.first().json;
const dates = d.last_date_per_hive || {};
const dateRows = Object.entries(dates).map(([h,dt]) => `<tr><td style='padding:4px 12px'>Colmena ${h}</td><td style='padding:4px 12px'>${dt}</td></tr>`).join('');
const htmlMessage = `
<h2 style='color:#27ae60'>✅ CSV de alzas actualizado</h2>
<table border='1' cellpadding='0' cellspacing='0' style='border-collapse:collapse'>
  <tr><td style='padding:6px 12px'><strong>Fecha</strong></td><td style='padding:6px 12px'>${d.run_date || 'N/A'}</td></tr>
  <tr><td style='padding:6px 12px'><strong>Estado</strong></td><td style='padding:6px 12px'>${d.status || 'ok'}</td></tr>
  <tr><td style='padding:6px 12px'><strong>Filas totales</strong></td><td style='padding:6px 12px'>${d.total_feat_rows || 'N/A'}</td></tr>
  <tr><td style='padding:6px 12px'><strong>Tiempo</strong></td><td style='padding:6px 12px'>${d.elapsed_s ? d.elapsed_s + 's' : 'N/A'}</td></tr>
</table>
${dateRows ? `<h3>Última fecha por colmena:</h3><table border='1' cellpadding='0' cellspacing='0' style='border-collapse:collapse'>${dateRows}</table>` : ''}
<hr/>
<p style='color:#888;font-size:12px'>Bee Monitor · UAB Apiary · TFG Miguel Arpa</p>
`;
return [{ json: { htmlMessage, run_date: d.run_date, status: d.status, total_feat_rows: d.total_feat_rows } }];
